import urllib.request, re
from html.parser import HTMLParser
url='https://douglasmitchell.info/'
html=urllib.request.urlopen(url, timeout=20).read().decode('utf-8', 'replace')
print('STATUS_OK', len(html))
print('TITLE', re.search(r'<title[^>]*>(.*?)</title>', html, re.I|re.S).group(1).strip())
for name in ['description','viewport','robots']:
    m=re.search(rf'<meta[^>]+name=["\']{name}["\'][^>]+content=["\'](.*?)["\']', html, re.I|re.S)
    print('META', name, m.group(1).strip() if m else 'MISSING')
class P(HTMLParser):
    def __init__(self):
        super().__init__(); self.links=[]
    def handle_starttag(self, tag, attrs):
        d=dict(attrs)
        if tag=='a' and 'href' in d:
            self.links.append(d['href'])
p=P(); p.feed(html)
seen=[]
for href in p.links:
    if href not in seen:
        seen.append(href)
print('LINKS')
for href in seen[:80]:
    print(href)
